import react, { useState, useMemo } from 'react';

const records = [
    { id: 1, name: 'adam', age: 25 },
    { id: 2, name: 'james', age: 30 },
    { id: 3, name: 'nick', age: 28 },
    { id: 4, name: 'john', age: 29 }
];

export default function datatable() {
    const [sortConfig, setsortconfig] = useState({ key: null, direction: 'asc' });
    const [filtertext, setfiltertext] = useState('');

    const sortedandfiltereddata = useMemo(() => {
        let processed = [...records];

        if (filtertext) {
            processed = processed.filter(item =>
                item.name.toLowerCase().includes(filtertext.toLowerCase())
            );
        }

        if (sortConfig.key) {
            processed.sort((a, b) => {
                if (a[sortConfig.key] < b[sortConfig.key]) return sortConfig.direction === 'asc' ? -1 : 1;
                if (a[sortConfig.key] > b[sortConfig.key]) return sortConfig.direction === 'asc' ? 1 : -1;
                return 0;
            });
        }

        return processed;
    }, [records, sortConfig, filtertext]);

    const requestsort = (key) => {
        let direction = 'asc';
        if (sortConfig.key === key && sortConfig.direction === 'asc') {
            direction = 'desc';
        }
        setsortconfig({ key, direction });
    };

    const getarrow = (columnkey) => {
        if (sortConfig.key !== columnkey) return '↕';
        return sortConfig.direction === 'asc' ? '↑' : '↓';
    };

    return (
        <div>
            <input
                type="text"
                placeholder="filter by name"
                value={filtertext}
                onchangecomponent={(e) => setfiltertext(e.target.value)}
            />
            <table border="1">
                <thead>
                    <tr>
                        <th onClick={() => requestsort('id')}>id {getarrow('id')}</th>
